using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace ResearchAgent;

public sealed class ResearchTools : IDisposable
{
    private readonly HttpClient _httpClient = new();
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Search the web for information on a topic. Returns relevant result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&format=json&srlimit=5&utf8=1";

            var response = await _httpClient.GetFromJsonAsync<WikiSearchResponse>(url, cancellationToken);

            if (response?.Query?.Search is not { Count: > 0 })
                return $"No results found for '{query}'.";

            var results = response.Query.Search
                .Select((r, i) => $"{i + 1}. **{r.Title}**\n   {StripHtml(r.Snippet)}")
                .ToList();

            return $"Search results for '{query}':\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.Message}). The web search API may be unavailable.";
        }
    }

    [Description("Save a research note with a title and content. Use this to record key findings.")]
    public string TakeNote(
        [Description("Short title for the note")] string title,
        [Description("The note content")] string content)
    {
        _notes.Add((title, content));
        return $"✅ Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var formatted = _notes
            .Select((n, i) => $"Note #{i + 1} — {n.Title}\n{n.Content}")
            .ToList();

        return string.Join("\n\n---\n\n", formatted);
    }

    public void Dispose() => _httpClient.Dispose();

    private static string StripHtml(string html) =>
        System.Text.RegularExpressions.Regex.Replace(html, "<.*?>", string.Empty);
}

// JSON models for the Wikipedia API response
file sealed class WikiSearchResponse
{
    [JsonPropertyName("query")]
    public WikiQuery? Query { get; set; }
}

file sealed class WikiQuery
{
    [JsonPropertyName("search")]
    public List<WikiSearchResult> Search { get; set; } = [];
}

file sealed class WikiSearchResult
{
    [JsonPropertyName("title")]
    public string Title { get; set; } = "";

    [JsonPropertyName("snippet")]
    public string Snippet { get; set; } = "";
}

