+var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";
+
+IChatClient chatClient = new OpenAIClient(apiKey)
+    .GetChatClient(modelId)
+    .AsIChatClient();
+
+var researchTools = new ResearchTools();
+
+var searchMethod = typeof(ResearchTools).GetMethod(nameof(ResearchTools.SearchWeb))!;
+var takeNoteMethod = typeof(ResearchTools).GetMethod(nameof(ResearchTools.TakeNote))!;
+var getNotesMethod = typeof(ResearchTools).GetMethod(nameof(ResearchTools.GetNotes))!;
+
+var tools = new List<AITool>
+{
+    AIFunctionFactory.Create(searchMethod, researchTools),
+    AIFunctionFactory.Create(takeNoteMethod, researchTools),
+    AIFunctionFactory.Create(getNotesMethod, researchTools),
+};
+
+var agent = new ChatClientAgent(
+    chatClient: chatClient,
+    options: new ChatClientAgentOptions
+    {
+        Instructions = """
+            You are a research agent. Your job is to thoroughly research a given topic
+            using the tools available to you.
+
+            Follow this process:
+            1. Break the topic into 2–3 key subtopics or questions.
+            2. Use SearchWeb to find information on each subtopic.
+            3. Use TakeNote to record important findings as you discover them.
+            4. After gathering enough information, use GetNotes to review all findings.
+            5. Provide a well-organized summary of your research with key takeaways.
+
+            Be thorough but concise. Always ground your summary in the search results.
+            """,
+        AgentName = "ResearchAgent",
+        Description = "Researches topics using web search and note-taking",
+        DefaultChatOptions = new ChatOptions
+        {
+            Temperature = 0f,
+            MaxOutputTokens = 2048,
+            Tools = tools,
+        },
+    });
+
+Console.WriteLine("🔍 Research Agent");
+Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
+Console.WriteLine();
+
+while (true)
+{
+    Console.Write("> ");
+    var input = Console.ReadLine();
+    if (string.IsNullOrWhiteSpace(input) || input.Equals("quit", StringComparison.OrdinalIgnoreCase))
+        break;
+
+    Console.WriteLine($"\n📚 Researching: {input}\n");
+
+    var session = new ChatClientAgentSession();
+
+    await foreach (var update in agent.RunStreamingAsync(
+        [$"Research this topic and provide a comprehensive summary: {input}"],
+        session,
+        cancellationToken: CancellationToken.None))
+    {
+        if (!string.IsNullOrEmpty(update.Text))
+            Console.Write(update.Text);
+    }
+
+    Console.WriteLine("\n");
+}
